# Python 3.11+
"""The recurrence SEAM (Strategy + Factory).

"When does this task run again ‚Äî if ever?" is the policy the product varies most:
fire once, fire every N seconds from the SCHEDULED time (fixed-rate), or fire N
seconds after the previous run FINISHED (fixed-delay). Each strategy answers one
question: given when the task was due and when it actually completed, what's the
NEXT run_at ‚Äî or None to stop.
"""

from __future__ import annotations

from abc import ABC, abstractmethod
from enum import Enum

from models import InvalidTaskError


class Recurrence(Enum):
    ONE_SHOT = "ONE_SHOT"
    FIXED_RATE = "FIXED_RATE"
    FIXED_DELAY = "FIXED_DELAY"


class RecurrenceStrategy(ABC):
    @abstractmethod
    def next_run(self, scheduled_for: float, completed_at: float) -> float | None:
        """Return the next run_at, or None if the task should not repeat."""


class OneShot(RecurrenceStrategy):
    """Fire exactly once."""

    def next_run(self, scheduled_for: float, completed_at: float) -> float | None:
        return None


class FixedRate(RecurrenceStrategy):
    """Fire every `interval` seconds measured from the SCHEDULED time, so the
    cadence is steady even if a run is briefly slow (e.g. every 0.05s on the dot)."""

    def __init__(self, interval: float) -> None:
        if interval <= 0:
            raise InvalidTaskError("fixed-rate interval must be positive")
        self.interval = interval

    def next_run(self, scheduled_for: float, completed_at: float) -> float | None:
        return scheduled_for + self.interval


class FixedDelay(RecurrenceStrategy):
    """Fire `interval` seconds after the previous run FINISHED, so two runs never
    overlap and slow runs push the schedule back."""

    def __init__(self, interval: float) -> None:
        if interval <= 0:
            raise InvalidTaskError("fixed-delay interval must be positive")
        self.interval = interval

    def next_run(self, scheduled_for: float, completed_at: float) -> float | None:
        return completed_at + self.interval


def make_recurrence(kind: Recurrence, interval: float = 0.0) -> RecurrenceStrategy:
    """Factory: translate the Recurrence enum into a strategy object."""
    if kind is Recurrence.ONE_SHOT:
        return OneShot()
    if kind is Recurrence.FIXED_RATE:
        return FixedRate(interval)
    if kind is Recurrence.FIXED_DELAY:
        return FixedDelay(interval)
    raise InvalidTaskError(f"unknown recurrence {kind}")
